#include <bits/stdc++.h>
using namespace std;

struct Fence {
    int x1, y1, x2, y2;
    // true if horizontal
    bool is_horizontal() const { return y1 == y2; }
};

struct Cow {
    int x, y;
};

// Disjoint Set Union (Union-Find)
struct DSU {
    vector<int> parent, sz;
    DSU(int n) {
        parent.resize(n);
        sz.resize(n, 1);
        for (int i = 0; i < n; i++) parent[i] = i;
    }
    int find(int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    void unite(int a, int b) {
        a = find(a); b = find(b);
        if (a == b) return;
        if (sz[a] < sz[b]) swap(a, b);
        parent[b] = a;
        sz[a] += sz[b];
    }
};

// Check if a point is inside the rect defined by two axis-aligned segments?
// Not needed directly. We need: can cow A walk to cow B without crossing any fence.
// Since fences only meet at endpoints, the fences partition the plane into regions.
// We can build a graph of "regions" by compressing coordinates and flood-fill.
// But simpler: treat each cow as a node, connect cows that can reach each other.
// Two cows are directly connected if the segment between them does not intersect any fence.
// However we can also use a union-find approach with a grid compression.

// Since N, C <= 500, we can do BFS/DFS on a compressed grid of size O(coord range).
// Coordinate compression: collect all unique x and y from fence endpoints and cows, plus +/-1 offsets.
// Then build a boolean grid where fences are walls, then flood-fill to assign region ids to cells,
// then assign each cow to its region, count sizes.

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, C;
    cin >> N >> C;
    vector<Fence> fences(N);
    vector<Cow> cows(C);

    vector<int> xs, ys;

    for (int i = 0; i < N; i++) {
        int x1, y1, x2, y2;
        cin >> x1 >> y1 >> x2 >> y2;
        fences[i] = {x1, y1, x2, y2};
        xs.push_back(x1); xs.push_back(x2);
        ys.push_back(y1); ys.push_back(y2);
    }
    for (int i = 0; i < C; i++) {
        int x, y;
        cin >> x >> y;
        cows[i] = {x, y};
        xs.push_back(x); ys.push_back(y);
    }

    // Add extra coordinates for adjacent cells (gap filling)
    // We need to include x+1, x-1 etc to represent open spaces properly.
    auto add_around = [&](vector<int>& v, int val) {
        v.push_back(val);
        v.push_back(val - 1);
        v.push_back(val + 1);
    };
    for (int x : xs) add_around(xs, x);
    for (int y : ys) add_around(ys, y);

    sort(xs.begin(), xs.end());
    xs.erase(unique(xs.begin(), xs.end()), xs.end());
    sort(ys.begin(), ys.end());
    ys.erase(unique(ys.begin(), ys.end()), ys.end());

    int H = (int)ys.size();
    int W = (int)xs.size();

    // Map coordinate to index
    auto idx_x = [&](int x) -> int {
        return (int)(lower_bound(xs.begin(), xs.end(), x) - xs.begin());
    };
    auto idx_y = [&](int y) -> int {
        return (int)(lower_bound(ys.begin(), ys.end(), y) - ys.begin());
    };

    // grid: true = blocked (fence cell)
    vector<vector<bool>> blocked(H, vector<bool>(W, false));

    // Mark fence cells
    for (auto& f : fences) {
        int x1 = idx_x(f.x1);
        int y1 = idx_y(f.y1);
        int x2 = idx_x(f.x2);
        int y2 = idx_y(f.y2);
        if (f.is_horizontal()) {
            // y1 == y2
            int y = y1;
            if (x1 > x2) swap(x1, x2);
            for (int x = x1; x <= x2; x++) {
                blocked[y][x] = true;
            }
        } else {
            // x1 == x2
            int x = x1;
            if (y1 > y2) swap(y1, y2);
            for (int y = y1; y <= y2; y++) {
                blocked[y][x] = true;
            }
        }
    }

    // Flood fill to assign region ids
    vector<vector<int>> region(H, vector<int>(W, -1));
    int region_count = 0;
    int dx[4] = {1, -1, 0, 0};
    int dy[4] = {0, 0, 1, -1};

    for (int y = 0; y < H; y++) {
        for (int x = 0; x < W; x++) {
            if (blocked[y][x]) continue;
            if (region[y][x] != -1) continue;
            queue<pair<int,int>> q;
            q.push({y, x});
            region[y][x] = region_count;
            while (!q.empty()) {
                auto [cy, cx] = q.front(); q.pop();
                for (int d = 0; d < 4; d++) {
                    int ny = cy + dy[d];
                    int nx = cx + dx[d];
                    if (ny < 0 || ny >= H || nx < 0 || nx >= W) continue;
                    if (blocked[ny][nx]) continue;
                    if (region[ny][nx] != -1) continue;
                    region[ny][nx] = region_count;
                    q.push({ny, nx});
                }
            }
            region_count++;
        }
    }

    // Count cows per region
    vector<int> cnt(region_count, 0);
    for (auto& cow : cows) {
        int x = idx_x(cow.x);
        int y = idx_y(cow.y);
        int r = region[y][x];
        if (r >= 0) cnt[r]++;
    }

    int ans = 0;
    for (int i = 0; i < region_count; i++) {
        ans = max(ans, cnt[i]);
    }
    cout << ans << "\n";

    return 0;
}
